// ============================================
// SPLIT DE MENSAGENS WHATSAPP
// Máximo: 2 mensagens
// ============================================

const mensagemOriginal = $input.first().json.output || "";

const LIMITE_UNICO = 500;
const PONTO_DIVISAO = 700;

// --------------------------------------------
// Funções auxiliares
// --------------------------------------------

function limparFormatacao(texto) {
  return texto.replace(/\*\*/g, "*").trim();
}

function extrairLinks(texto) {
  return texto.match(/https?:\/\/\S+|www\.\S+/gi) || [];
}

function removerLinks(texto) {
  return texto.replace(/https?:\/\/\S+|www\.\S+/gi, "").trim();
}

function encontrarQuebra(texto, ideal) {
  const pontos = [
    "\n\n",
    "\n",
    ". ",
    "! ",
    "? ",
    "; ",
    ", ",
    " "
  ];

  for (const p of pontos) {
    const pos = texto.lastIndexOf(p, ideal);
    if (pos > texto.length * 0.35) {
      return pos + p.length;
    }
  }

  return ideal;
}

// --------------------------------------------
// Início
// --------------------------------------------

if (!mensagemOriginal.trim()) {
  return [];
}

const texto = limparFormatacao(mensagemOriginal);

// Se houver exatamente dois blocos separados por linha em branco,
// envia cada bloco como uma mensagem.
const partesParagrafo = texto.split(/\n\s*\n/).filter(p => p.trim());

if (partesParagrafo.length === 2) {
  return partesParagrafo.map(parte => ({
    json: {
      message: parte.trim()
    }
  }));
}

// Links em mensagem própria
const links = extrairLinks(texto);

if (links.length) {
  const textoSemLinks = removerLinks(texto);

  const items = [];

  if (textoSemLinks) {
    if (textoSemLinks.length <= LIMITE_UNICO) {
      items.push({
        json: {
          message: textoSemLinks
        }
      });
    } else {
      const quebra = encontrarQuebra(textoSemLinks, PONTO_DIVISAO);

      items.push({
        json: {
          message: textoSemLinks.substring(0, quebra).trim()
        }
      });

      const restante = textoSemLinks.substring(quebra).trim();

      if (restante) {
        items.push({
          json: {
            message: restante
          }
        });
      }
    }
  }

  links.forEach(link => {
    items.push({
      json: {
        message: link
      }
    });
  });

  return items;
}

// Cabe em uma única mensagem
if (texto.length <= LIMITE_UNICO) {
  return [
    {
      json: {
        message: texto
      }
    }
  ];
}

// Divide em no máximo 2 mensagens
const quebra = encontrarQuebra(texto, PONTO_DIVISAO);

const primeira = texto.substring(0, quebra).trim();
const segunda = texto.substring(quebra).trim();

return [
  {
    json: {
      message: primeira
    }
  },
  ...(segunda
    ? [
        {
          json: {
            message: segunda
          }
        }
      ]
    : [])
];
